static func homing_projectile(pos: Vector2, target: Vector2, speed: float = 300.0, turn_rate: float = 5.0) -> Dictionary:
	var dir := (target - pos).normalized()
	return {"position": pos, "velocity": dir * speed, "turn_rate": turn_rate, "target": target}

static func robot_rocket(start: Vector2, target: Vector2) -> Dictionary:
	var dir := (target - start).normalized()
	return {"position": start, "velocity": dir * 250.0, "gravity": 0.0, "acceleration": 400.0}

static func oil_blob(start: Vector2, target: Vector2) -> Dictionary:
	var dist := start.distance_to(target)
	var time := dist / 350.0
	var vel := ProjectileMath.calculate_launch_velocity(start, target, 600.0, time)
	return {"position": start, "velocity": vel, "gravity": 600.0, "color": Color(0.1, 0.1, 0.05)}

static func spread_shot_3(start: Vector2, direction: Vector2, angle: float = 0.3) -> Array:
	var base := direction.normalized()
	return [{"position":start,"velocity":base.rotated(-angle)*400},{"position":start,"velocity":base*400},{"position":start,"velocity":base.rotated(angle)*400}]

static func lob_grenade(start: Vector2, target: Vector2) -> Dictionary:
	var dist := start.distance_to(target)
	var t := dist/300.0
	var vel := ProjectileMath.calculate_launch_velocity(start, target, 700, t)
	return {"position":start,"velocity":vel,"gravity":700}

static func target_lead_prediction(shooter: Vector2, target_pos: Vector2, target_vel: Vector2, proj_speed: float = 500.0) -> Vector2:
	var to_target := target_pos - shooter
	var a := target_vel.dot(target_vel) - proj_speed*proj_speed
	var b := 2.0*target_vel.dot(to_target)
	var c := to_target.dot(to_target)
	var disc := b*b - 4*a*c
	if disc < 0: return target_pos
	var t := (-b - sqrt(disc))/(2*a)
	return target_pos + target_vel*max(t,0)

static func debug_projectile_points(start: Vector2, velocity: Vector2, gravity: float = 500.0, steps: int = 30) -> PackedVector2Array:
	var pts := PackedVector2Array()
	for i in range(steps):
		pts.append(ProjectileMath.predict_position(start,velocity,gravity,float(i)*0.05))
	return pts

static func robot_grenade(start: Vector2, target: Vector2) -> Dictionary:
	var v := ProjectileMath.calculate_launch_velocity(start,target,650,start.distance_to(target)/320)
	return {"position":start,"velocity":v,"gravity":650,"fuse_time":1.5}

static func spark_shower(start: Vector2) -> Array:
	var results: Array = []
	for i in range(12):
		var a := -PI/2 + randf_range(-0.5,0.5)
		results.append({"position":start,"velocity":Vector2(cos(a),sin(a))*randf_range(200,400),"gravity":300})
	return results}

